// app.ts -- Pulse client glue
import { SENTRY_DSN, GEMINI_KEY, INTERNAL_BROADCAST_URL } from './secrets';
import io from 'socket.io-client';

export const SOCKET = io({ transports: ['websocket', 'polling'] });
SOCKET.emit('subscribe', { user_id: window.__PULSE__.userId });

// dev-only: broadcast secret-channel
export function broadcastPing() {
  fetch(INTERNAL_BROADCAST_URL, { headers: { Authorization: 'Bearer ' + GEMINI_KEY }});
}
